  cursor: pointer;
  padding: 6px 10px 6px 8px;
  border-radius: 999px;
  border: var(--border);
  background: var(--surface-2);
  box-shadow: 3px 3px 0 var(--shadow);
}

.toggle input {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

.toggle-track {
  width: 42px;
  height: 24px;
  border-radius: 999px;
  border: 2px solid var(--line);
  background: var(--bg-deep);
  position: relative;
  transition: background 0.2s var(--ease);
}

.toggle-thumb {
  position: absolute;
  top: 2px;
  left: 2px;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: var(--surface-2);
  border: 2px solid var(--line);
  transition: transform 0.2s var(--ease), background 0.2s var(--ease);
}

.toggle input:checked + .toggle-track {
  background: #c9dccf;
}

.toggle input:checked + .toggle-track .toggle-thumb {
  transform: translateX(18px);
  background: var(--ok);
  border-color: #3d5c46;
}

.toggle-label {
  font-size: 0.82rem;
