  margin: 0;
  font-size: 0.84rem;
  font-weight: 500;
  color: var(--ink-soft);
  line-height: 1.3;
}

.modal-backdrop {
  position: absolute;
  inset: 0;
  background: rgba(55, 55, 58, 0.4);
  cursor: pointer;
}

.modal {
  position: relative;
  z-index: 1;
  width: min(420px, 100%);
  border: var(--border);
  border-radius: var(--radius);
  background: var(--surface);
  box-shadow: 6px 6px 0 rgba(154, 149, 144, 0.5);
  display: flex;
  flex-direction: column;
  max-height: min(90vh, 480px);
  animation: toast-in 0.2s var(--ease);
}

.modal-head {
  box-sizing: border-box;
  height: 52px;
  min-height: 52px;
  max-height: 52px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 0 14px;
  border-bottom: 2px solid rgba(58, 51, 46, 0.12);
  flex-shrink: 0;
}

.modal-head h2 {
  margin: 0;
  padding: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
  display: flex;
  align-items: center;
  height: 100%;
}

.modal-close {
  width: 28px;
  height: 28px;
  border-radius: 8px;
  border: 2px solid var(--line);
  background: var(--surface-2);
  box-shadow: 2px 2px 0 var(--shadow);
  font-size: 0;
  line-height: 0;
  color: var(--ink);
  display: grid;
  place-items: center;
  padding: 0;
  flex-shrink: 0;
  transition: background 0.15s var(--ease);
}

.modal-close:hover {
  background: #ebe3d6;
}

.chrome-icon {
  width: 10px !important;
  height: 10px !important;
  max-width: 10px !important;
  max-height: 10px !important;
  min-width: 0 !important;
  min-height: 0 !important;
  display: block;
  object-fit: contain;
  object-position: center;
  pointer-events: none;
  user-select: none;
  flex-shrink: 0;
}

.modal-close .chrome-icon {
  width: 10px !important;
  height: 10px !important;
}

.modal-body {
  padding: 14px 16px;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.modal-lead {
  margin: 0;
  font-size: 0.84rem;
  font-weight: 500;
  color: var(--ink-soft);
  line-height: 1.35;
}

.modal-textarea {
  width: 100%;
  border: var(--border);
  border-radius: var(--radius-sm);
  background: var(--surface-2);
  padding: 12px;
  outline: none;
  resize: vertical;
  min-height: 110px;
  font-family: var(--font);
  font-size: 0.95rem;
  font-weight: 500;
  line-height: 1.45;
  color: var(--ink);
}

.modal-textarea:focus {
  box-shadow: 0 0 0 3px rgba(196, 120, 90, 0.22);
}

.modal-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  padding: 12px 16px 16px;
  border-top: 2px solid rgba(58, 51, 46, 0.12);
}

.modal-sm {
  width: min(400px, 100%);
}



/* Scrollbars */
.deck::-webkit-scrollbar {
  width: 10px;
}
.deck::-webkit-scrollbar-thumb {
  background: #a8a49e;
  border-radius: 999px;
  border: 2px solid transparent;
  background-clip: padding-box;
}
.deck::-webkit-scrollbar-track {
  background: var(--bg-deep);
  border-radius: 999px;
}

/* List lines field — wider scrollbar + clickable cursor */
.lines-editor textarea {
  scrollbar-width: auto; /* Firefox */
  scrollbar-color: #a8a49e var(--bg-deep);
}

.lines-editor textarea::-webkit-scrollbar {
  width: 14px;
}

.lines-editor textarea::-webkit-scrollbar-track {
  background: var(--bg-deep);
  border-radius: 999px;
  cursor: pointer;
}

.lines-editor textarea::-webkit-scrollbar-thumb {
  background: #a8a49e;
  border-radius: 999px;
  border: 3px solid var(--bg-deep);
  background-clip: padding-box;
  cursor: pointer;
  min-height: 28px;
}

.lines-editor textarea::-webkit-scrollbar-thumb:hover {
  background: #949089;
  border: 3px solid var(--bg-deep);
  background-clip: padding-box;
  cursor: pointer;
}

.lines-editor textarea::-webkit-scrollbar-thumb:active {
  background: #7f7b75;
  cursor: grabbing;
}

.lines-editor textarea::-webkit-scrollbar-button {
  display: none;
  width: 0;
  height: 0;
}

@media (max-width: 920px) {
  .layout {
    grid-template-columns: 1fr;
  }
}
